example.code:
from fastapi import FastAPI, HTTPException from openai import AsyncOpenAI from guardrails_pipeline import GuardrailsPipeline, GuardrailConfig
app = FastAPI() client = AsyncOpenAI() pipeline = GuardrailsPipeline( client=client, model="gpt-4o", config=GuardrailConfig( enable_pii_detection=True, enable_injection_detection=True, enable_content_moderation=True, enable_hallucination_detection=False, ), )
@app.post("/chat") async def chat(body: dict): result = await pipeline.arun(body["message"]) if not result.is_safe: raise HTTPException(400, {"violations": result.violations}) return {"reply": result.filtered_output, "violations": result.violations}

@app.post("/chat-bad")
async def chat_bad(body: dict, openai_key: str):
    p = GuardrailsPipeline(client=AsyncOpenAI(api_key=openai_key), model="gpt-4o")
    result = await p.arun(body["message"])
    return {"reply": result.filtered_output}
